// Initialize query parameters
const currentHour = new Date().getHours();

return [{
  json: {
    timestamp: new Date().toISOString(),
    current_hour: currentHour,
    is_morning: currentHour === 9,
    sent_count: 0,
    failed_count: 0
  }
}];

// Parse opportunity records
const response = $node['Fetch Unnotified Opportunities'].json || { records: [] };

if (!response.records || response.records.length === 0) {
  return [{
    json: {
      opportunities: [],
      total_count: 0,
      message: 'No unnotified opportunities found'
    }
  }];
}

const opportunities = response.records.map((record, idx) => ({
  json: {
    index: idx + 1,
    record_id: record.id,
    supplier_id: record.fields?.supplier_id || '',
    opportunity_id: record.fields?.opportunity_id || '',
    opportunity_name: record.fields?.opportunity_name || 'Unknown',
    supplier_email: record.fields?.supplier_email || '',
    match_score: record.fields?.match_score || 0,
    match_reason: record.fields?.match_reason || '',
    contract_deadline: record.fields?.contract_deadline || '',
    contract_value_usd: record.fields?.contract_value_usd || 0,
    status: record.fields?.status || 'Available'
  }
}));

return opportunities;

// Create lookup map of suppliers by ID
const suppliersResponse = $node['Fetch Supplier Details'].json || { records: [] };
const supplierMap = {};

if (suppliersResponse.records && suppliersResponse.records.length > 0) {
  suppliersResponse.records.forEach(record => {
    supplierMap[record.id] = {
      legal_name: record.fields?.legal_name || '',
      contact_name: record.fields?.contact_name || '',
      email: record.fields?.email || record.fields?.business_email || '',
      notification_preference: record.fields?.notification_preference || 'daily'
    };
  });
}

const opportunity = $node['Parse Opportunities'].json;
const supplier = supplierMap[opportunity.supplier_id] || {
  legal_name: 'Unknown',
  contact_name: 'Contact',
  email: opportunity.supplier_email,
  notification_preference: 'daily'
};

return [{
  json: {
    ...opportunity,
    contact_name: supplier.contact_name,
    legal_name: supplier.legal_name,
    email: supplier.email,
    notification_preference: supplier.notification_preference
  }
}];

// Check if we should send notification based on preference
const opportunity = $node['Enrich with Supplier Details'].json;
const currentHour = $node['Initialize Notification Query'].json.current_hour;
const isNineAM = currentHour === 9;

// Send if: immediate preference OR (daily preference AND current hour is 9 AM)
const shouldSend = 
  opportunity.notification_preference === 'immediate' || 
  (opportunity.notification_preference === 'daily' && isNineAM);

return [{
  json: {
    ...opportunity,
    should_send: shouldSend,
    reason: shouldSend ? 
      (opportunity.notification_preference === 'immediate' ? 'Immediate preference' : 'Daily at 9 AM') :
      (opportunity.notification_preference === 'daily' ? 'Waiting for 9 AM' : 'Unknown preference')
  }
}];

// Log completion
const emailSent = $node['Send Email via SendGrid'].statusCode === 202 || $node['Send Email via SendGrid'].statusCode === 200;
const opportunity = $node['Format Email Content'].json;

return [{
  json: {
    status: emailSent ? 'success' : 'failed',
    supplier: opportunity.legal_name,
    opportunity: opportunity.opportunity_name,
    recipient: opportunity.email,
    timestamp: new Date().toISOString()
  }
}];
